compliant:
inline int cube(int i) {
  return i * i * i;
}

void func(void) {
  int i = 2;
  int a = cube(++i); // yields 27
  // ...
}

template<typename T>
constexpr T max(const T& a, const T& b) {
  return (a > b) ? a : b;
}
